import{_ as d,o as r,c as e,a2 as a}from"./chunks/framework.DnrXFDHb.js";const C=JSON.parse('{"title":"电力新能源 · 关键术语表","description":"","frontmatter":{},"headers":[],"relativePath":"电力新能源/关键术语表.md","filePath":"电力新能源/关键术语表.md","lastUpdated":1781535932000}'),o={name:"电力新能源/关键术语表.md"};function n(i,t,h,l,c,s){return r(),e("div",null,[...t[0]||(t[0]=[a('<h1 id="电力新能源-·-关键术语表" tabindex="-1">电力新能源 · 关键术语表 <a class="header-anchor" href="#电力新能源-·-关键术语表" aria-label="Permalink to &quot;电力新能源 · 关键术语表&quot;">​</a></h1><p><strong>用途：</strong> PE/VC 一级市场投资研究参考</p><hr><h2 id="一、光伏" tabindex="-1">一、光伏 <a class="header-anchor" href="#一、光伏" aria-label="Permalink to &quot;一、光伏&quot;">​</a></h2><table tabindex="0"><thead><tr><th>术语</th><th>中文</th><th>说明</th></tr></thead><tbody><tr><td>PV</td><td>光伏</td><td>Photovoltaic，光生伏特效应发电</td></tr><tr><td>PERC</td><td>钝化发射极背面电池</td><td>Passivated Emitter and Rear Cell，当前主流 P 型电池技术</td></tr><tr><td>TOPCon</td><td>隧穿氧化层钝化接触电池</td><td>Tunnel Oxide Passivated Contact，当前主流 N 型电池，量产效率 25-26%</td></tr><tr><td>HJT / HIT</td><td>异质结电池</td><td>Heterojunction Technology，效率 25.5-26.5%，工艺步骤少但设备贵</td></tr><tr><td>BC / IBC</td><td>背接触电池</td><td>Back Contact，正面无栅线，美观+高效率，隆基主力方向</td></tr><tr><td>Perovskite</td><td>钙钛矿太阳能电池</td><td>下一代薄膜电池技术，实验室效率&gt;33%（叠层），稳定性攻关中</td></tr><tr><td>BIPV</td><td>建筑光伏一体化</td><td>Building Integrated PV，光伏组件作为建筑材料</td></tr><tr><td>BAPV</td><td>建筑附着光伏</td><td>Building Attached PV，光伏组件附着于既有建筑</td></tr><tr><td>LCOE</td><td>平准化度电成本</td><td>Levelized Cost of Electricity，光伏发电全生命周期度电成本</td></tr><tr><td>硅料/多晶硅</td><td>Polysilicon</td><td>光伏产业链最上游原料，西门子法为主，颗粒硅新技术</td></tr><tr><td>金刚线</td><td>Diamond Wire</td><td>硅片切割用线，线径更细→出片更多→成本更低</td></tr><tr><td>N 型 vs P 型</td><td>N/P 型硅片</td><td>N 型（磷掺杂）效率更高、衰减更低，当前替代 P 型中</td></tr><tr><td>双面率</td><td>Bifaciality</td><td>双面发电组件背面/正面功率比</td></tr><tr><td>衰减率</td><td>Degradation</td><td>光伏组件每年发电效率下降比例（P型首年2-3%，N型&lt;1%）</td></tr></tbody></table><h2 id="二、储能" tabindex="-1">二、储能 <a class="header-anchor" href="#二、储能" aria-label="Permalink to &quot;二、储能&quot;">​</a></h2><table tabindex="0"><thead><tr><th>术语</th><th>中文</th><th>说明</th></tr></thead><tbody><tr><td>LFP</td><td>磷酸铁锂电池</td><td>LiFePO4，当前储能主力电化学路线</td></tr><tr><td>NCM/NCA</td><td>三元锂电池</td><td>能量密度高，用于动力电池，储能较少</td></tr><tr><td>钠离子电池</td><td>Sodium-ion Battery</td><td>钠替代锂，原料丰富成本低，能量密度偏低，2025-2026量产元年</td></tr><tr><td>全钒液流电池</td><td>Vanadium Redox Flow Battery (VRFB)</td><td>长时储能（4-12h），循环寿命&gt;20年，但钒成本高</td></tr><tr><td>铁铬液流电池</td><td>Iron-Chromium Flow Battery</td><td>原料更便宜，能量密度更低，国家电投主导</td></tr><tr><td>压缩空气储能</td><td>CAES</td><td>Compressed Air Energy Storage，大规模长时储能，选址依赖洞穴</td></tr><tr><td>飞轮储能</td><td>Flywheel Energy Storage</td><td>短时高频响应，用于调频</td></tr><tr><td>超级电容</td><td>Supercapacitor</td><td>短时大功率，秒级响应</td></tr><tr><td>BMS</td><td>电池管理系统</td><td>Battery Management System，监控电压/温度/SOC/SOH</td></tr><tr><td>EMS</td><td>能量管理系统</td><td>Energy Management System，充放电调度策略</td></tr><tr><td>PCS</td><td>储能变流器</td><td>Power Conversion System，AC/DC 双向变换</td></tr><tr><td>SOC</td><td>荷电状态</td><td>State of Charge，电池剩余电量百分比</td></tr><tr><td>SOH</td><td>健康状态</td><td>State of Health，电池老化程度</td></tr><tr><td>DOD</td><td>放电深度</td><td>Depth of Discharge，充放电区间</td></tr><tr><td>C-rate</td><td>充放电倍率</td><td>1C = 1小时充满/放完</td></tr><tr><td>RTE</td><td>往返效率</td><td>Round-Trip Efficiency，充放电能量转换效率</td></tr><tr><td>独立储能</td><td>Standalone Storage</td><td>独立参与电力市场的储能电站</td></tr><tr><td>容量电价</td><td>Capacity Payment</td><td>为可用容量付费，保障储能收益的机制</td></tr></tbody></table><h2 id="三、风电" tabindex="-1">三、风电 <a class="header-anchor" href="#三、风电" aria-label="Permalink to &quot;三、风电&quot;">​</a></h2><table tabindex="0"><thead><tr><th>术语</th><th>中文</th><th>说明</th></tr></thead><tbody><tr><td>LCOW</td><td>平准化度电成本（风电）</td><td>Levelized Cost of Wind</td></tr><tr><td>陆上风电</td><td>Onshore Wind</td><td>陆地上安装，当前LCOE已低于火电</td></tr><tr><td>海上风电</td><td>Offshore Wind</td><td>海洋中安装，利用更高风速，LCOE仍在下降通道</td></tr><tr><td>浮式风电</td><td>Floating Offshore Wind</td><td>深水区（&gt;60m）使用浮式基础，早期技术</td></tr><tr><td>单桩</td><td>Monopile</td><td>固定式基础，用于浅海</td></tr><tr><td>导管架</td><td>Jacket</td><td>固定式基础，用于较深海</td></tr><tr><td>DFIG</td><td>双馈异步发电机</td><td>Doubly-Fed Induction Generator，当前主流风机技术</td></tr><tr><td>直驱永磁</td><td>Direct Drive PMSG</td><td>无齿轮箱，可靠性高，金风/海装等主力</td></tr><tr><td>容量因子</td><td>Capacity Factor</td><td>实际发电/理论最大发电，海上风电 40-55%</td></tr><tr><td>叶片回收</td><td>Blade Recycling</td><td>退役叶片（玻纤/碳纤复合材料）回收利用</td></tr><tr><td>风功率预测</td><td>Wind Power Forecasting</td><td>AI/ML 预测风功率，电网调度需求</td></tr></tbody></table><h2 id="四、氢能" tabindex="-1">四、氢能 <a class="header-anchor" href="#四、氢能" aria-label="Permalink to &quot;四、氢能&quot;">​</a></h2><table tabindex="0"><thead><tr><th>术语</th><th>中文</th><th>说明</th></tr></thead><tbody><tr><td>灰氢</td><td>Grey Hydrogen</td><td>天然气重整制氢，有碳排放</td></tr><tr><td>蓝氢</td><td>Blue Hydrogen</td><td>灰氢+CCUS（碳捕集），低碳</td></tr><tr><td>绿氢</td><td>Green Hydrogen</td><td>可再生能源电解水制氢，零碳</td></tr><tr><td>PEM 电解槽</td><td>Proton Exchange Membrane</td><td>质子交换膜电解水，响应快，效率高，贵金属催化剂</td></tr><tr><td>AEM 电解槽</td><td>Anion Exchange Membrane</td><td>阴离子交换膜电解水，非贵金属，研发阶段</td></tr><tr><td>SOEC</td><td>固体氧化物电解槽</td><td>Solid Oxide Electrolyzer，高温电解，效率最高</td></tr><tr><td>LOHC</td><td>液态有机氢载体</td><td>Liquid Organic Hydrogen Carrier，常温常压储运氢</td></tr><tr><td>氢脆</td><td>Hydrogen Embrittlement</td><td>金属在氢气中韧性下降，材料科学难题</td></tr><tr><td>FCV / FCEV</td><td>燃料电池汽车</td><td>Fuel Cell Electric Vehicle</td></tr><tr><td>膜电极</td><td>MEA</td><td>Membrane Electrode Assembly，燃料电池核心部件</td></tr><tr><td>双极板</td><td>Bipolar Plate</td><td>燃料电池电堆组成部分，金属/石墨两种路线</td></tr><tr><td>CCUS</td><td>碳捕集利用与封存</td><td>Carbon Capture, Utilization and Storage</td></tr></tbody></table><h2 id="五、智能电网-虚拟电厂-电力市场" tabindex="-1">五、智能电网/虚拟电厂/电力市场 <a class="header-anchor" href="#五、智能电网-虚拟电厂-电力市场" aria-label="Permalink to &quot;五、智能电网/虚拟电厂/电力市场&quot;">​</a></h2><table tabindex="0"><thead><tr><th>术语</th><th>中文</th><th>说明</th></tr></thead><tbody><tr><td>VPP</td><td>虚拟电厂</td><td>Virtual Power Plant，聚合分布式资源参与电力市场</td></tr><tr><td>DER</td><td>分布式能源资源</td><td>Distributed Energy Resource，包括分布式光伏/储能/充电桩</td></tr><tr><td>需求侧响应</td><td>Demand Response (DR)</td><td>用户侧根据电价信号调整用电行为</td></tr><tr><td>辅助服务</td><td>Ancillary Services</td><td>调频/调峰/备用/黑启动等保障电网稳定服务</td></tr><tr><td>现货市场</td><td>Spot Market</td><td>日前+实时，即期电力交易市场</td></tr><tr><td>中长期市场</td><td>Forward Market</td><td>月度/季度/年度电力合约交易</td></tr><tr><td>绿证</td><td>Green Electricity Certificate (GEC)</td><td>可再生能源发电环境属性凭证</td></tr><tr><td>微电网</td><td>Microgrid</td><td>局部发配用一体化，可离网运行</td></tr><tr><td>AMI</td><td>高级量测体系</td><td>Advanced Metering Infrastructure，智能电表+通信网络</td></tr><tr><td>配电自动化</td><td>Distribution Automation</td><td>配网侧远程监控/故障定位隔离恢复</td></tr><tr><td>电力物联网</td><td>Power IoT</td><td>电网侧广泛部署的传感/通信/边缘计算</td></tr></tbody></table><h2 id="六、碳市场" tabindex="-1">六、碳市场 <a class="header-anchor" href="#六、碳市场" aria-label="Permalink to &quot;六、碳市场&quot;">​</a></h2><table tabindex="0"><thead><tr><th>术语</th><th>中文</th><th>说明</th></tr></thead><tbody><tr><td>ETS</td><td>碳排放权交易系统</td><td>Emission Trading System，总量控制+交易</td></tr><tr><td>CCER</td><td>国家核证自愿减排量</td><td>自愿减排项目碳信用，2024年重启</td></tr><tr><td>CBAM</td><td>碳边境调节机制</td><td>Carbon Border Adjustment Mechanism，欧盟碳关税</td></tr><tr><td>碳配额</td><td>Carbon Allowance/Allowance</td><td>控排企业的排放权配额</td></tr><tr><td>碳足迹</td><td>Carbon Footprint</td><td>产品全生命周期碳排放</td></tr><tr><td>CEMS</td><td>碳排放连续监测系统</td><td>Continuous Emission Monitoring System</td></tr><tr><td>VCS</td><td>自愿碳标准</td><td>Verified Carbon Standard，国际自愿减排标准</td></tr><tr><td>绿电交易</td><td>Green Power Trading</td><td>可再生能源电量的独立交易机制</td></tr></tbody></table>',15)])])}const y=d(o,[["render",n]]);export{C as __pageData,y as default};
